CREATE TABLE pages (\n    id INT PRIMARY KEY AUTO_INCREMENT,\n    title VARCHAR(255) NOT NULL,\n    content TEXT NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP\n);\n\nCREATE TABLE blog_categories (\n    id INT PRIMARY KEY AUTO_INCREMENT,\n    name VARCHAR(255) NOT NULL UNIQUE,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE blog_tags (\n    id INT PRIMARY KEY AUTO_INCREMENT,\n    name VARCHAR(255) NOT NULL UNIQUE,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE blog_posts (\n    id INT PRIMARY KEY AUTO_INCREMENT,\n    title VARCHAR(255) NOT NULL,\n    content TEXT NOT NULL,\n    category_id INT,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,\n    FOREIGN KEY (category_id) REFERENCES blog_categories(id)\n);\n\nCREATE TABLE blog_post_tags (\n    blog_post_id INT,\n    blog_tag_id INT,\n    PRIMARY KEY (blog_post_id, blog_tag_id),\n    FOREIGN KEY (blog_post_id) REFERENCES blog_posts(id),\n    FOREIGN KEY (blog_tag_id) REFERENCES blog_tags(id)\n);\n\nCREATE TABLE comments (\n    id INT PRIMARY KEY AUTO_INCREMENT,\n    blog_post_id INT,\n    commenter_name VARCHAR(255),\n    comment_text TEXT,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    FOREIGN KEY (blog_post_id) REFERENCES blog_posts(id)\n);\n\nCREATE TABLE site_settings (\n    id INT PRIMARY KEY AUTO_INCREMENT,\n    setting_key VARCHAR(255) NOT NULL UNIQUE,\n    setting_value TEXT NOT NULL\n);\n\nCREATE TABLE newsletters (\n    id INT PRIMARY KEY AUTO_INCREMENT,\n    title VARCHAR(255) NOT NULL,\n    content TEXT NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE newsletter_subscribers (\n    id INT PRIMARY KEY AUTO_INCREMENT,\n    email VARCHAR(255) NOT NULL UNIQUE,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Sample Data\nINSERT INTO pages (title, content) VALUES ('Home', 'Welcome to our website!');\nINSERT INTO blog_categories (name) VALUES ('Technology'), ('Health'), ('Lifestyle');\nINSERT INTO blog_tags (name) VALUES ('Innovation'), ('Fitness'), ('Travel');\nINSERT INTO blog_posts (title, content, category_id) VALUES ('First Post', 'This is the first blog post.', 1);\nINSERT INTO comments (blog_post_id, commenter_name, comment_text) VALUES (1, 'John Doe', 'Great post!');\nINSERT INTO site_settings (setting_key, setting_value) VALUES ('site_name', 'GlobexSky'), ('contact_email', 'contact@globexsky.com');\nINSERT INTO newsletters (title, content) VALUES ('Monthly Update', 'Here are the updates for this month.');\nINSERT INTO newsletter_subscribers (email) VALUES ('subscriber@example.com');\n